+import Quickshell
+import QtQuick
+
+FocusScope {
+  id: root
+
+  required property var statusData
+  readonly property var results: statusData.appLauncherResults
+  implicitWidth: 480
+  implicitHeight: 398
+
+  function syncSearchText() {
+    if (searchInput.text !== statusData.appLauncherQuery) {
+      searchInput.text = statusData.appLauncherQuery;
+      searchInput.cursorPosition = searchInput.text.length;
+    }
+  }
+
+  function revealSelection() {
+    if (statusData.appLauncherSelectedIndex >= 0 && results.length > 0)
+      appList.positionViewAtIndex(statusData.appLauncherSelectedIndex,
+        ListView.Contain);
+  }
+
+  onEnabledChanged: {
+    if (enabled) {
+      syncSearchText();
+      Qt.callLater(() => {
+        searchInput.forceActiveFocus();
+        revealSelection();
+      });
+    }
+  }
+
+  Connections {
+    target: statusData
+
+    function onAppLauncherQueryChanged() {
+      root.syncSearchText();
+    }
+
+    function onAppLauncherResultsChanged() {
+      Qt.callLater(() => root.revealSelection());
+    }
+
+    function onAppLauncherSelectedIndexChanged() {
+      root.revealSelection();
+    }
+  }
+
+  Item {
+    anchors.fill: parent
+
+    Text {
+      id: searchIcon
+      anchors.left: parent.left
+      anchors.leftMargin: 16
+      y: 9
+      width: 22
+      height: 24
+      horizontalAlignment: Text.AlignHCenter
+      verticalAlignment: Text.AlignVCenter
+      text: "󰍉"
+      color: "#ff33cc"
+      font.family: "Ubuntu Nerd Font"
+      font.pixelSize: 17
+      font.bold: true
+    }
+
+    TextInput {
+      id: searchInput
+      anchors.left: searchIcon.right
+      anchors.leftMargin: 10
+      anchors.right: resultCount.left
+      anchors.rightMargin: 12
+      y: 7
+      height: 28
+      verticalAlignment: TextInput.AlignVCenter
+      color: "#cad3f5"
+      selectionColor: "#ff33cc"
+      selectedTextColor: "#181926"
+      clip: true
+      font.family: "Ubuntu Nerd Font"
+      font.pixelSize: 14
+      font.bold: true
+      cursorVisible: activeFocus
+
+      onTextEdited: statusData.setAppLauncherQuery(text)
+
+      Keys.onPressed: event => {
+        const control = event.modifiers & Qt.ControlModifier;
+        if (event.key === Qt.Key_Down || (control && event.key === Qt.Key_N)
+            || event.key === Qt.Key_Tab) {
+          statusData.moveAppLauncherSelection(1);
+          event.accepted = true;
+        } else if (event.key === Qt.Key_Up || (control && event.key === Qt.Key_P)
+            || (event.key === Qt.Key_Backtab)) {
+          statusData.moveAppLauncherSelection(-1);
+          event.accepted = true;
+        } else if (event.key === Qt.Key_PageDown) {
+          statusData.moveAppLauncherSelection(8);
+          event.accepted = true;
+        } else if (event.key === Qt.Key_PageUp) {
+          statusData.moveAppLauncherSelection(-8);
+          event.accepted = true;
+        } else if (event.key === Qt.Key_Home && control) {
+          statusData.appLauncherSelectedIndex = 0;
+          event.accepted = true;
+        } else if (event.key === Qt.Key_End && control
+            && statusData.appLauncherResults.length > 0) {
+          statusData.appLauncherSelectedIndex
+            = statusData.appLauncherResults.length - 1;
+          event.accepted = true;
+        } else if (event.key === Qt.Key_Return || event.key === Qt.Key_Enter) {
+          statusData.launchSelectedApp(statusData.appLauncherSelectedIndex,
+            (event.modifiers & Qt.ShiftModifier) !== 0);
+          event.accepted = true;
+        } else if (event.key === Qt.Key_Escape) {
+          statusData.hideAppLauncher();
+          event.accepted = true;
+        }
+      }
+    }
+
+    Text {
+      anchors.left: searchInput.left
+      anchors.right: searchInput.right
+      y: searchInput.y
+      height: searchInput.height
+      visible: searchInput.text === ""
+      verticalAlignment: Text.AlignVCenter
+      text: "Search applications…"
+      color: "#6e738d"
+      font.family: "Ubuntu Nerd Font"
+      font.pixelSize: 14
+      font.bold: true
+    }
+
+    Text {
+      id: resultCount
+      anchors.right: parent.right
+      anchors.rightMargin: 16
+      y: 9
+      width: 88
+      height: 24
+      horizontalAlignment: Text.AlignRight
+      verticalAlignment: Text.AlignVCenter
+      text: results.length + (results.length === 1 ? " APP" : " APPS")
+      color: results.length > 0 ? "#a6da95" : "#ed8796"
+      font.family: "Ubuntu Nerd Font"
+      font.pixelSize: 10
+      font.bold: true
+    }
+
+    Rectangle {
+      anchors.left: parent.left
+      anchors.right: parent.right
+      anchors.leftMargin: 14
+      anchors.rightMargin: 14
+      y: 41
+      height: 1
+      color: "#363a4f"
+    }
+
+    ListView {
+      id: appList
+      anchors.left: parent.left
+      anchors.right: parent.right
+      y: 48
+      height: 342
+      clip: true
+      model: root.results
+      currentIndex: statusData.appLauncherSelectedIndex
+      boundsBehavior: Flickable.StopAtBounds
+      highlightMoveDuration: 120
+      highlightResizeDuration: 120
+
+      delegate: Item {
+        id: appRow
+        required property var modelData
+        required property int index
+        readonly property var entry: modelData.entry
+        readonly property bool selected: index === statusData.appLauncherSelectedIndex
+        readonly property int toplevelRevision: statusData.appToplevelRevision
+        readonly property var runningToplevel: {
+          const revision = toplevelRevision;
+          return statusData.appToplevelFor(entry);
+        }
+
+        width: appList.width
+        height: 42
+
+        Rectangle {
+          anchors.fill: parent
+          anchors.leftMargin: 8
+          anchors.rightMargin: 8
+          anchors.topMargin: 2
+          anchors.bottomMargin: 2
+          radius: 10
+          color: appRow.selected ? "#363a4f" : "transparent"
+
+          Behavior on color { ColorAnimation { duration: 90 } }
+        }
+
+        Rectangle {
+          id: iconFrame
+          anchors.left: parent.left
+          anchors.leftMargin: 16
+          anchors.verticalCenter: parent.verticalCenter
+          width: 30
+          height: 30
+          radius: 8
+          color: appRow.selected ? "#494d64" : "#24273a"
+
+          Image {
+            id: appIcon
+            anchors.fill: parent
+            anchors.margins: 3
+            source: Quickshell.iconPath(appRow.entry.icon,
+              "application-x-executable")
+            sourceSize.width: 24
+            sourceSize.height: 24
+            fillMode: Image.PreserveAspectFit
+            asynchronous: true
+            cache: true
+          }
+
+          Text {
+            visible: appIcon.status === Image.Error
+            anchors.centerIn: parent
+            text: "󰀻"
+            color: "#ff33cc"
+            font.family: "Ubuntu Nerd Font"
+            font.pixelSize: 15
+            font.bold: true
+          }
+        }
+
+        Text {
+          anchors.left: iconFrame.right
+          anchors.leftMargin: 11
+          anchors.right: launchHint.left
+          anchors.rightMargin: 12
+          y: 4
+          height: 18
+          verticalAlignment: Text.AlignVCenter
+          text: appRow.entry.name
+          color: appRow.selected ? "#ffffff" : "#cad3f5"
+          elide: Text.ElideRight
+          font.family: "Ubuntu Nerd Font"
+          font.pixelSize: 13
+          font.bold: true
+        }
+
+        Text {
+          anchors.left: iconFrame.right
+          anchors.leftMargin: 11
+          anchors.right: launchHint.left
+          anchors.rightMargin: 12
+          y: 21
+          height: 15
+          verticalAlignment: Text.AlignVCenter
+          text: appRow.entry.genericName !== "" ? appRow.entry.genericName
+            : appRow.entry.comment
+          color: "#939ab7"
+          elide: Text.ElideRight
+          font.family: "Ubuntu Nerd Font"
+          font.pixelSize: 10
+          font.bold: true
+        }
+
+        Rectangle {
+          anchors.right: launchHint.left
+          anchors.rightMargin: 5
+          anchors.verticalCenter: parent.verticalCenter
+          width: 7
+          height: 7
+          radius: 3.5
+          visible: appRow.runningToplevel !== null
+          color: "#eed49f"
+        }
+
+        Text {
+          id: launchHint
+          anchors.right: parent.right
+          anchors.rightMargin: 18
+          anchors.verticalCenter: parent.verticalCenter
+          width: 24
+          horizontalAlignment: Text.AlignHCenter
+          text: appRow.selected ? "󰌑" : ""
+          color: "#ff33cc"
+          font.family: "Ubuntu Nerd Font"
+          font.pixelSize: 14
+          font.bold: true
+        }
+
+        MouseArea {
+          anchors.fill: parent
+          cursorShape: Qt.PointingHandCursor
+          onClicked: statusData.launchSelectedApp(appRow.index)
+        }
+      }
+
+      WheelHandler {
+        acceptedDevices: PointerDevice.Mouse | PointerDevice.TouchPad
+        onWheel: event => {
+          if (event.angleDelta.y < 0)
+            statusData.moveAppLauncherSelection(1);
+          else if (event.angleDelta.y > 0)
+            statusData.moveAppLauncherSelection(-1);
+        }
+      }
+    }
+
+    Text {
+      visible: results.length === 0
+      anchors.left: parent.left
+      anchors.right: parent.right
+      y: 165
+      height: 40
+      horizontalAlignment: Text.AlignHCenter
+      verticalAlignment: Text.AlignVCenter
+      text: "No matching applications"
+      color: "#939ab7"
+      font.family: "Ubuntu Nerd Font"
+      font.pixelSize: 13
+      font.bold: true
+    }
+  }
+}
