+
+        width: appList.width
+        height: 42
+
+        Rectangle {
+          anchors.fill: parent
+          anchors.leftMargin: 8
+          anchors.rightMargin: 8
+          anchors.topMargin: 2
+          anchors.bottomMargin: 2
