+        }
+
+        Text {
+          id: launchHint
+          anchors.right: parent.right
+          anchors.rightMargin: 18
+          anchors.verticalCenter: parent.verticalCenter
+          width: 24
+          horizontalAlignment: Text.AlignHCenter
+          text: appRow.selected ? "󰌑" : ""
+          color: "#ff33cc"
+          font.family: "Ubuntu Nerd Font"
+          font.pixelSize: 14
+          font.bold: true
+        }
+
+        MouseArea {
+          anchors.fill: parent
