  1039	          ? status.updates.map(update => update.name + ": " + update.date).join("\n")
  1040	          : status.message || "System is up to date";
  1041	      } else {
  1042	        // Compatibility with the preserved Waybar helper cache format.
  1043	        root.nixIcon = status.alt === "has-updates" ? "" : "";
  1044	        root.nixTooltip = status.tooltip || "System is up to date";
  1045	        const lines = status.alt === "has-updates"
  1046	          ? root.nixTooltip.split("\n").filter(line => line.trim() !== "") : [];
  1047	        root.nixUpdates = lines.map(line => {
  1048	          const separator = line.lastIndexOf(": ");
  1049	          return separator >= 0
  1050	            ? { "name": line.slice(0, separator), "date": line.slice(separator + 2) }
  1051	            : { "name": line, "date": "" };
  1052	        });
  1053	      }
