  2	  topBarConfig = pkgs.runCommand "quickshell-top-bar" {
  3	    nativeBuildInputs = [pkgs.qt6Packages.qtshadertools];
  4	  } ''
  5	    cp -R ${./quickshell/top-bar} "$out"
  6	    chmod -R u+w "$out"
  7	    qsb --qt6 \
  8	      -o "$out/shaders/activity-border.frag.qsb" \
  9	      "$out/shaders/activity-border.frag"
